import org.elasticsearch.ElasticsearchStatusException;
import org.elasticsearch.action.admin.indices.delete.DeleteIndexRequest;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.support.master.AcknowledgedResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.client.indices.CreateIndexRequest;
import org.elasticsearch.client.indices.GetIndexRequest;
import org.elasticsearch.common.settings.Settings;
import org.elasticsearch.common.xcontent.XContentType;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import jakarta.annotation.PostConstruct;
import java.io.IOException;
import java.util.Map;

@Service
public class ProductIndexService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    @Value("${elasticsearch.index.products:products}")
    private String productsIndex;

    public ProductIndexService(RestHighLevelClient client, ObjectMapper objectMapper) {
        this.client = client;
        this.objectMapper = objectMapper;
    }

    @PostConstruct
    public void ensureIndex() throws IOException {
        GetIndexRequest get = new GetIndexRequest(productsIndex);
        boolean exists = client.indices().exists(get, RequestOptions.DEFAULT);
        if (!exists) {
            CreateIndexRequest create = new CreateIndexRequest(productsIndex);
            create.settings(Settings.builder()
                    .put("index.number_of_shards", 1)
                    .put("index.number_of_replicas", 0)
                    .put("analysis.analyzer.folded.type", "custom")
                    .put("analysis.analyzer.folded.tokenizer", "standard")
                    .putList("analysis.analyzer.folded.filter", "lowercase", "asciifolding")
            );

            String mapping = "{\n" +
                    "  \"dynamic\": true,\n" +
                    "  \"properties\": {\n" +
                    "    \"sku\": {\"type\": \"keyword\"},\n" +
                    "    \"name\": {\"type\": \"text\", \"analyzer\": \"folded\", \"fields\": {\"keyword\": {\"type\": \"keyword\", \"ignore_above\": 256}}},\n" +
                    "    \"description\": {\"type\": \"text\", \"analyzer\": \"folded\"},\n" +
                    "    \"brand\": {\"type\": \"keyword\"},\n" +
                    "    \"categories\": {\"type\": \"keyword\"},\n" +
                    "    \"tags\": {\"type\": \"keyword\"},\n" +
                    "    \"price\": {\"type\": \"double\"},\n" +
                    "    \"currency\": {\"type\": \"keyword\"},\n" +
                    "    \"inStock\": {\"type\": \"boolean\"},\n" +
                    "    \"rating\": {\"type\": \"double\"},\n" +
                    "    \"reviewCount\": {\"type\": \"integer\"},\n" +
                    "    \"attributes\": {\"type\": \"object\", \"dynamic\": true}\n" +
                    "  }\n" +
                    "}";
            create.mapping(mapping, XContentType.JSON);
            client.indices().create(create, RequestOptions.DEFAULT);
        }
    }

    public void indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            throw new IllegalArgumentException("Product id is required");
        }
        Map<String, Object> source = objectMapper.convertValue(product, new TypeReference<Map<String, Object>>() {});
        IndexRequest req = new IndexRequest(productsIndex).id(product.getId()).source(source);
        client.index(req, RequestOptions.DEFAULT);
    }

    public void deleteAndRecreateIndex() throws IOException {
        try {
            AcknowledgedResponse del = client.indices().delete(new DeleteIndexRequest(productsIndex), RequestOptions.DEFAULT);
        } catch (ElasticsearchStatusException e) {
            // ignore if missing
        }
        ensureIndex();
    }
}

