package com.example.search.service;

import com.example.search.dto.FacetBucketDto;
import com.example.search.dto.SearchRequestDto;
import com.example.search.dto.SearchResponseDto;
import com.example.search.model.Product;
import com.example.search.model.SearchQueryLog;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.index.query.BoolQueryBuilder;
import org.elasticsearch.index.query.MultiMatchQueryBuilder;
import org.elasticsearch.index.query.Operator;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.SearchHit;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.*;

@Service
public class ProductSearchService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;
    private final SearchQueryLogService logService;

    @Value("${elasticsearch.index.products:products}")
    private String productsIndex;

    @Value("${search.facets.fields:brand,categories,tags,inStock}")
    private String facetFieldsCsv;

    public ProductSearchService(RestHighLevelClient client, ObjectMapper objectMapper, SearchQueryLogService logService) {
        this.client = client;
        this.objectMapper = objectMapper;
        this.logService = logService;
    }

    public SearchResponseDto search(SearchRequestDto req, String customerId, String sessionId) throws IOException {
        SearchRequest searchRequest = new SearchRequest(productsIndex);
        SearchSourceBuilder source = new SearchSourceBuilder();

        BoolQueryBuilder bool = QueryBuilders.boolQuery();

        String q = req.getQuery();
        if (q == null || q.isBlank()) {
            bool.must(QueryBuilders.matchAllQuery());
        } else {
            MultiMatchQueryBuilder mm = QueryBuilders.multiMatchQuery(q, "name^3", "description", "brand^2", "categories^2", "tags")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .operator(Operator.AND)
                    .fuzziness("AUTO");
            bool.must(mm);
        }

        if (req.getTermFilters() != null) {
            for (Map.Entry<String, List<String>> e : req.getTermFilters().entrySet()) {
                if (e.getKey() == null || e.getKey().isBlank() || e.getValue() == null || e.getValue().isEmpty()) continue;
                bool.filter(QueryBuilders.termsQuery(e.getKey(), e.getValue()));
            }
        }

        if (req.getInStock() != null) {
            bool.filter(QueryBuilders.termQuery("inStock", req.getInStock()));
        }

        if (req.getMinPrice() != null || req.getMaxPrice() != null) {
            var range = QueryBuilders.rangeQuery("price");
            if (req.getMinPrice() != null) range.gte(req.getMinPrice());
            if (req.getMaxPrice() != null) range.lte(req.getMaxPrice());
            bool.filter(range);
        }

        source.query(bool);

        int page = req.getPage() == null ? 0 : Math.max(0, req.getPage());
        int size = req.getSize() == null ? 10 : Math.min(200, Math.max(1, req.getSize()));
        source.from(page * size);
        source.size(size);

        String sort = req.getSort();
        if (sort != null && !sort.isBlank()) {
            switch (sort) {
                case "price_asc" -> source.sort("price", SortOrder.ASC);
                case "price_desc" -> source.sort("price", SortOrder.DESC);
                case "rating_desc" -> source.sort("rating", SortOrder.DESC);
                case "name_asc" -> source.sort("name.keyword", SortOrder.ASC);
                default -> { }
            }
        }

        for (String field : parseFacetFields()) {
            source.aggregation(AggregationBuilders.terms("facet_" + field).field(field).size(50));
        }

        searchRequest.source(source);

        SearchResponse resp = client.search(searchRequest, RequestOptions.DEFAULT);

        List<Product> products = new ArrayList<>();
        for (SearchHit hit : resp.getHits().getHits()) {
            Product p = objectMapper.readValue(hit.getSourceAsString(), Product.class);
            p.setId(hit.getId());
            products.add(p);
        }

        Map<String, List<FacetBucketDto>> facets = new LinkedHashMap<>();
        for (String field : parseFacetFields()) {
            Terms terms = resp.getAggregations().get("facet_" + field);
            if (terms == null) continue;
            List<FacetBucketDto> buckets = new ArrayList<>();
            for (Terms.Bucket b : terms.getBuckets()) {
                buckets.add(new FacetBucketDto(String.valueOf(b.getKey()), b.getDocCount()));
            }
            facets.put(field, buckets);
        }

        SearchQueryLog log = new SearchQueryLog();
        log.setQuery(req.getQuery());
        log.setCustomerId(customerId);
        log.setSessionId(sessionId);
        Map<String, Object> filters = new LinkedHashMap<>();
        if (req.getTermFilters() != null) filters.put("termFilters", req.getTermFilters());
        if (req.getMinPrice() != null) filters.put("minPrice", req.getMinPrice());
        if (req.getMaxPrice() != null) filters.put("maxPrice", req.getMaxPrice());
        if (req.getInStock() != null) filters.put("inStock", req.getInStock());
        log.setFilters(filters.isEmpty() ? null : filters);
        log.setPage(page);
        log.setSize(size);
        log.setSort(sort);
        logService.log(log);

        long total = resp.getHits().getTotalHits() == null ? products.size() : resp.getHits().getTotalHits().value;
        return new SearchResponseDto(total, products, facets);
    }

    private List<String> parseFacetFields() {
        String csv = facetFieldsCsv == null ? "" : facetFieldsCsv.trim();
        if (csv.isEmpty()) return List.of("brand", "categories", "tags", "inStock");
        String[] parts = csv.split(",");
        List<String> out = new ArrayList<>();
        for (String p : parts) {
            String f = p.trim();
            if (!f.isEmpty()) out.add(f);
        }
        return out.isEmpty() ? List.of("brand", "categories", "tags", "inStock") : out;
    }
}

package com.example.search.controller;

import com.example.search.model.Product;
import com.example.search.service.ProductIndexService;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexService indexService;

    public ProductController(ProductIndexService indexService) {
        this.indexService = indexService;
    }

    @PutMapping("/{id}")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void upsert(@PathVariable String id, @RequestBody Product product) throws IOException {
        product.setId(id);
        indexService.indexProduct(product);
    }

    @PostMapping
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void upsertBody(@RequestBody Product product) throws IOException {
        indexService.indexProduct(product);
    }

    @PostMapping("/reindex")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void reindex() throws IOException {
        indexService.deleteAndRecreateIndex();
    }
}

